const alertStages = [
  { days: 45, stage: 'alerted_45d', urgency: '🟡 REMINDER', msg: '📅 Research Phase: Look for alternatives.' },
  { days: 30, stage: 'alerted_30d', urgency: '🟠 ATTENTION', msg: '💰 Quote Phase: Get competitor pricing.' },
  { days: 14, stage: 'alerted_14d', urgency: '🔴 URGENT', msg: '🎯 Decision Phase: Finalize negotiation.' },
  { days: 7, stage: 'alerted_7d', urgency: '🚨 FINAL NOTICE', msg: '⚠️ Action Phase: Confirm or Cancel.' }
];

const now = new Date();
const results = [];
const processed = new Set();

for (const item of items) {
  const data = item.json;
  const status = data['Status'] || 'Active';
  const rawDate = data['Renewal Date'];

  // Skip invalid/completed contracts
  if (!rawDate || status.includes('Cancelled') || status.includes('Renewed')) continue;

  // Deduplication
  const contractId = `${data['Contract Name']}-${rawDate}`;
  if (processed.has(contractId)) continue;

  // VALIDATION
  const contractName = data['Contract Name']?.trim();
  if (!contractName) continue;

  const currentCost = Number(data['Current Annual Cost']);
  if (isNaN(currentCost) || currentCost < 0) continue;

  const url = data['Vendor Pricing URL'];
  if (!url || (!url.startsWith('http://') && !url.startsWith('https://'))) continue;

  // DATE CALCULATION (using standard JS Date)
  const renewalDate = new Date(rawDate);
  const diffInMs = renewalDate - now;
  const daysUntil = Math.ceil(diffInMs / (1000 * 60 * 60 * 24));

  // Skip expired or invalid dates
  if (isNaN(daysUntil) || daysUntil < 0) continue;

  // SLUG FOR UTM (deterministic fallback using row number)
  let slug = contractName
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-+|-+$/g, '')
    .substring(0, 50);

  // Fallback: use row number for consistency (not timestamp)
  if (!slug) slug = `contract-row-${data.rowNumber || 'unknown'}`;

  // MULTI-STAGE FILTER WITH CATCH-UP WINDOW
  for (const alert of alertStages) {
    // Window: If within alert.days OR slightly past it (catch-up for missed runs)
    const inWindow = daysUntil <= alert.days && daysUntil > (alert.days - 5);
    const notYetAlerted = !status.includes(alert.stage);

    if (inWindow && notYetAlerted) {
      processed.add(contractId);

      results.push({
        json: {
          contractName: contractName,
          vendorName: data['Vendor Name'] || 'Unknown Vendor',
          renewalDate: rawDate,
          currentCost: currentCost,
          pricingUrl: url,
          status: status,
          rowNumber: data.rowNumber,
          daysUntilRenewal: daysUntil,
          _alertStage: alert.stage,
          _alertMessage: alert.msg,
          urgency: alert.urgency,
          contractSlug: slug,
          _isAlert: true,
          potentialSavingsMin: Math.round(currentCost * 0.15),
          potentialSavingsMax: Math.round(currentCost * 0.25)
        }
      });
      break;
    }
  }
}

// EMPTY RESULT HANDLER
if (results.length === 0) {
  return [{ 
    json: { 
      _isAlert: false, 
      summaryMsg: `✅ Daily renewal check complete.\n\nReviewed ${items.length} contract${items.length !== 1 ? 's' : ''}.\nNo renewals in alert windows (45d, 30d, 14d, 7d).` 
    } 
  }];
}

return results;
